if __name__ == "__main__":
    # Setup dummy data for forward guidance
    B, C, H, W = 2, 3, 64, 64
    z = torch.randn(B, C, H, W)
    t_scalar = 5

    # Dummy denoiser: returns random noise prediction
    def dummy_denoise(x: Tensor, t: Union[int, Tensor]) -> Tensor:
        return torch.randn_like(x) * 0.1

    # Alpha schedule: constant alpha = 0.9
    def alpha_schedule(t: Union[int, Tensor]) -> Tensor:
        return torch.tensor(0.9, dtype=torch.float32)

    # Guidance network: identity
    def dummy_guidance(x: Tensor) -> Tensor:
        return x

    # Loss: mean squared error to zero
    def mse_loss(x: Tensor) -> Tensor:
        return (x ** 2).mean(dim=(1, 2, 3))

    # Scale schedule: constant 0.5
    def scale_schedule(t: Union[int, Tensor]) -> float:
        return 0.5

    eps_g, z0_hat = forward_universal_guidance(
        z, t_scalar, dummy_denoise, alpha_schedule,
        dummy_guidance, mse_loss, scale_schedule
    )
    print("Forward Guidance Output Shapes:", eps_g.shape, z0_hat.shape)

    # Setup dummy model for backward guidance
    class DummyModel:
        def apply_model(self, x, t, cond):
            return torch.randn_like(x) * 0.1

        def decode_first_stage_with_grad(self, z0):
            return z0  # identity decoder

    model = DummyModel()
    cond = torch.zeros(B, C, H, W)
    # alphas cumprod: linear from 1 to 0
    alphas = torch.linspace(1.0, 0.1, steps=10)

    t_vector = torch.randint(0, len(alphas), (B,))
    eps_tilde = backward_universal_guidance(
        z, t_vector, model, cond, alphas,
        dummy_guidance, mse_loss, num_grad_steps=2, guidance_weight=0.7
    )
    print("Backward Guidance Output Shape:", eps_tilde.shape)
